#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int xor=0, x;
        for(int i=0;i<N;i++){
            scanf("%d",&x);
            xor ^= x;
        }
        if(xor==0) printf("Bob\n");
        else printf("Alice\n");
    }
    return 0;
}

